class Student {
  String name;
  int score;

  void study() {
    score = score + 5;
  }
}

Student alice = new Student();
alice.name = "Alice";
alice.score = 80;

Student omar = new Student();
omar.name = "Omar";
omar.score = 70;

alice.study();

Student.name = "Alice"; // incorrect for an instance field

Student alice = new Student();
alice.name = "Alice"; // correct: use an object reference
